CREATE TABLE public.replies (keyword TEXT PRIMARY KEY, content JSONB NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now()); GRANT ALL ON public.replies TO service_role; ALTER TABLE public.replies ENABLE ROW LEVEL SECURITY; CREATE TABLE public.bot_config (id INT PRIMARY KEY DEFAULT 1, delete_after_seconds INT NOT NULL DEFAULT 0, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), CONSTRAINT bot_config_single_row CHECK (id = 1)); GRANT ALL ON public.bot_config TO service_role; ALTER TABLE public.bot_config ENABLE ROW LEVEL SECURITY; INSERT INTO public.bot_config (id, delete_after_seconds) VALUES (1, 0); CREATE TABLE public.admin_state (chat_id BIGINT PRIMARY KEY, state TEXT, pending_keyword TEXT, selected_keyword TEXT, updated_at TIMESTAMPTZ NOT NULL DEFAULT now()); GRANT ALL ON public.admin_state TO service_role; ALTER TABLE public.admin_state ENABLE ROW LEVEL SECURITY;